// WF-KEEPWARM: Mantiene el webhook gateway activo para evitar cold start
// Envia un payload de 'status update' que WF01 filtra silenciosamente
// (los status updates son descartados en el nodo '3. Extraer Mensaje' -> skip:true)
const helpers = this.helpers;
const WEBHOOK_URL = $env.WEBHOOK_URL || $env.N8N_HOST || $env.N8N_WEBHOOK_URL || 'http://localhost:5678';

// Payload que simula un status update de WhatsApp (skip=true en WF01, sin procesamiento real)
const dummyPayload = {
  entry: [{
    changes: [{
      value: {
        statuses: [{ id: 'keepwarm', status: 'delivered', timestamp: String(Date.now()) }]
        // Sin campo 'messages' → WF01 nodo 3 devuelve skip:true → nodo 4 lo filtra
      }
    }]
  }]
};

try {
  await helpers.httpRequest({
    method: 'POST',
    url: `${WEBHOOK_URL}/webhook/whatsapp-gateway`,
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify(dummyPayload)
  });
  return [{ json: { action: 'keepwarm_ok', ts: new Date().toISOString() } }];
} catch(e) {
  return [{ json: { action: 'keepwarm_error', error: e.message } }];
}
